/* Hybrid Tile Studio v10 — friendly product shell and World Director */
(() => {
    "use strict";
    const api = window.HybridTileStudio;
    const production = window.HybridTileStudioProduction;
    if (!api || !production || !/^(10|11|12|13|14|15|16|17|18)\./.test(String(api.version))) return;
    const $ = id => document.getElementById(id);
    const clone = value => value === undefined ? undefined : JSON.parse(JSON.stringify(value));
    const integer = (value, fallback = 0) => Number.isFinite(Number(value)) ? Math.trunc(Number(value)) : fallback;
    const escapeHtml = value => String(value ?? "").replace(/[&<>"']/g, character => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;", "'": "&#39;" })[character]);
    const safeId = value => String(value || "").trim().toLowerCase().replace(/[^a-z0-9._:-]+/g, "-").replace(/^-+|-+$/g, "").slice(0, 128);
    const parseJson = (text, fallback = null) => { try { return JSON.parse(String(text || "")); } catch (error) { if (fallback !== null) return fallback; throw error; } };
    const valueFromText = text => { const value = String(text ?? "").trim(); if (!value) return ""; try { return JSON.parse(value); } catch (_) { return value; } };
    const uid = prefix => `${prefix}-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 7)}`;
    const defaults = {
        mode: "simple", workspace: "home", onboardingComplete: false, commandHistory: [],
        world: { clock: { enabled: true, day: 1, hour: 8, minuteOfHour: 0, framesPerMinute: 60, daysPerSeason: 30, seasons: ["spring", "summer", "autumn", "winter"] }, stateDefaults: {}, zones: [], entities: [], resources: [], variants: [], npcs: [], ruleLayers: [], biomeGraphs: [], tests: [] },
        packs: [], breakpoints: [], timeline: [], selectedTestId: null, overlayEnabled: true
    };
    const model = Object.assign(clone(defaults), api.getExtensionData("product-v10", {}));
    model.world = Object.assign(clone(defaults.world), model.world || {});
    for (const key of ["zones", "entities", "resources", "variants", "npcs", "ruleLayers", "biomeGraphs", "tests"]) if (!Array.isArray(model.world[key])) model.world[key] = [];
    if (!Array.isArray(model.packs)) model.packs = [];
    if (!Array.isArray(model.breakpoints)) model.breakpoints = [];
    if (!Array.isArray(model.timeline)) model.timeline = [];
    let persistTimer = 0; let suppressRecipeSaveSync = false;
    const persist = () => { clearTimeout(persistTimer); persistTimer = setTimeout(() => api.setExtensionData("product-v10", model).catch(reportError), 80); };
    const reportError = error => { console.error(error); api.status(error?.message || String(error), true); announce(error?.message || String(error)); };
    const safe = callback => async event => { event?.preventDefault?.(); try { await callback(event); } catch (error) { reportError(error); } };
    const announce = value => { if ($("v10Announcer")) $("v10Announcer").textContent = String(value || ""); };

    const WORKSPACES = {
        home: { label: "Home", icon: "⌂", description: "Your project at a glance" },
        maps: { label: "Map", icon: "▦", panel: "tilePanel", description: "Paint and shape maps" },
        events: { label: "Events", icon: "!", panel: "eventsPanel", description: "Characters and interactions" },
        recipes: { label: "World", icon: "✦", panel: "recipesPanel", description: "Rules that make the world react" },
        create: { label: "Create", icon: "✎", panel: "generatorsPanel", description: "Generate and reuse content" },
        content: { label: "Packs", icon: "◇", view: "packs", description: "Reusable content packs" },
        test: { label: "Test", icon: "✓", view: "test", description: "Scenarios and live debugging" },
        publish: { label: "Ship", icon: "→", view: "publish", description: "Validate and build" }
    };

    const COMMANDS = [
        ...Object.entries(WORKSPACES).map(([id, value]) => ({ id: `go-${id}`, label: `Go to ${value.label}`, hint: value.description, run: () => navigate(id) })),
        { id: "open-project", label: "Open RPG Maker project", hint: "Choose a project folder", run: () => $("openProjectButton").click() },
        { id: "save-all", label: "Save everything", hint: "Atomic save across open maps", run: () => $("saveAllButton").click() },
        { id: "new-recipe", label: "New World Recipe", hint: "Start a friendly WHEN / IF / THEN flow", run: () => { navigate("recipes"); $("v9NewRecipeButton").click(); setTimeout(enhanceRecipeForm, 0); } },
        { id: "run-checkup", label: "Run project checkup", hint: "Recipes, maps, references, and release readiness", run: () => { navigate("publish"); runReleaseCheck(); } },
        { id: "push-live", label: "Send World Recipes to playtest", hint: "Hot reload through the local bridge", run: pushToPlaytest },
        { id: "toggle-pro", label: "Toggle Simple / Pro mode", hint: "Show or hide advanced controls", run: () => setMode(model.mode === "simple" ? "pro" : "simple") },
        { id: "help", label: "Open Help Center", hint: "Guided tours, shortcuts, and concepts", run: () => openHelp() }
    ];

    function injectShell() {
        document.documentElement.classList.add("v10-product");
        document.body.insertAdjacentHTML("afterbegin", '<div id="v10Announcer" class="sr-only" aria-live="polite"></div>');
        const header = document.querySelector(".topbar");
        header.insertAdjacentHTML("afterend", `<nav id="v10Nav" class="v10-nav" aria-label="Main workspaces">${Object.entries(WORKSPACES).map(([id, item]) => `<button type="button" data-v10-workspace="${id}" title="${escapeHtml(item.description)}"><span class="v10-nav-icon" aria-hidden="true">${item.icon}</span><span>${item.label}</span></button>`).join("")}<span class="v10-nav-space"></span><button id="v10SearchButton" type="button" class="v10-command-button" title="Command palette (Ctrl+K)"><span aria-hidden="true">⌕</span><span>Find</span><kbd>Ctrl K</kbd></button><div class="v10-mode-switch" role="group" aria-label="Interface detail"><button type="button" data-v10-mode="simple">Simple</button><button type="button" data-v10-mode="pro">Pro</button></div><button id="v10HelpButton" type="button" class="v10-round-button" aria-label="Help">?</button></nav>`);
        document.querySelector(".workspace").insertAdjacentHTML("beforebegin", homeMarkup());
        document.querySelector(".workspace").insertAdjacentHTML("afterend", `<section id="v10Workbench" class="v10-workbench hidden" aria-label="Product workspace"><header><div><button id="v10WorkbenchBack" type="button" class="v10-back">← Back</button><p id="v10WorkbenchEyebrow">Hybrid Tile Studio</p><h1 id="v10WorkbenchTitle">Workspace</h1><p id="v10WorkbenchDescription"></p></div><div id="v10WorkbenchActions" class="v10-workbench-actions"></div></header><div id="v10WorkbenchBody" class="v10-workbench-body"></div></section>`);
        document.body.insertAdjacentHTML("beforeend", commandPaletteMarkup() + helpMarkup() + onboardingMarkup() + '<input id="v10WorldPackFile" type="file" accept=".json,.htgworld,application/json" hidden>');
        const topbar = document.querySelector(".topbar");
        topbar.querySelector(".brand strong").textContent = "Hybrid Tile Studio";
        topbar.querySelector(".brand small").textContent = "Make worlds that feel alive";
        topbar.querySelector(".brand-mark").textContent = "H";
        const toolbar = topbar.querySelector(".toolbar");
        toolbar.classList.add("v10-utility-toolbar");
        $("openProjectButton").textContent = "Open Project"; $("saveAllButton").textContent = "Save All";
        document.querySelector(".canvas-stage").insertAdjacentHTML("beforeend", '<canvas id="v10RecipeOverlay" class="v10-recipe-overlay" aria-hidden="true"></canvas>');
        $("recipesPanel").querySelector(".panel-header").insertAdjacentHTML("beforebegin", worldSystemsMarkup());
        markAdvancedControls();
    }

    function worldSystemsMarkup() {
        return `<section id="v10WorldSystems" class="v10-world-systems"><header><div><span class="v10-kicker">WORLD DIRECTOR</span><strong>World Systems</strong><small>Time, places, resources, and map forms</small></div><button id="v10SaveWorldSystems" type="button">Save</button></header><nav aria-label="World systems"><button type="button" data-v10-world-tab="clock" class="active">Time</button><button type="button" data-v10-world-tab="zones">Zones</button><button type="button" data-v10-world-tab="entities">Places</button><button type="button" data-v10-world-tab="resources">Resources</button><button type="button" data-v10-world-tab="variants">Variants</button></nav><div id="v10WorldSystemBody"></div></section>`;
    }

    function homeMarkup() {
        return `<section id="v10Home" class="v10-home"><div class="v10-hero"><div><span class="v10-kicker">HYBRID TILE STUDIO 10</span><h1>What would you like to make?</h1><p>Maps, events, and living-world rules are organized into clear, guided spaces. Your original project data stays in your control.</p><div class="v10-hero-actions"><button type="button" class="v10-big-primary" data-v10-home-action="open">Open a project</button><button type="button" data-v10-home-action="tour">Take the quick tour</button></div></div><div class="v10-hero-orbit" aria-hidden="true"><span>WHEN</span><span>IF</span><span>THEN</span><i></i></div></div><div class="v10-card-grid">${Object.entries(WORKSPACES).filter(([id]) => !["home", "publish"].includes(id)).map(([id, item], index) => `<button type="button" class="v10-home-card color-${index % 5}" data-v10-workspace="${id}"><span class="v10-card-icon" aria-hidden="true">${item.icon}</span><strong>${item.label}</strong><small>${escapeHtml(item.description)}</small><span class="v10-card-arrow">→</span></button>`).join("")}</div><aside class="v10-project-health"><div><span class="v10-health-dot"></span><strong id="v10HomeProject">No project open</strong><small id="v10HomeSummary">Open an RPG Maker MZ folder to begin.</small></div><button type="button" data-v10-workspace="publish">Project Checkup →</button></aside></section>`;
    }

    function commandPaletteMarkup() { return `<dialog id="v10CommandPalette" class="v10-command-palette"><form method="dialog"><div class="v10-command-search"><span aria-hidden="true">⌕</span><input id="v10CommandInput" type="search" placeholder="Find a tool or action…" autocomplete="off" aria-label="Find a tool or action"><kbd>Esc</kbd></div><div id="v10CommandList" class="v10-command-list" role="listbox"></div><footer><span>↑↓ Move</span><span>Enter Choose</span><span>Ctrl K Open anywhere</span></footer></form></dialog>`; }
    function helpMarkup() { return `<dialog id="v10Help" class="v10-help"><form method="dialog"><header><div><span class="v10-kicker">HELP CENTER</span><h2>Build with confidence</h2></div><button value="close" aria-label="Close">×</button></header><div class="v10-help-grid"><button type="button" data-v10-tour="true"><strong>5-minute guided tour</strong><small>Learn the new workspace one step at a time.</small></button><button type="button" data-v10-help-nav="recipes"><strong>World Recipe basics</strong><small>Understand WHEN, IF, and THEN without JSON.</small></button><button type="button" data-v10-help-nav="test"><strong>Testing and debugging</strong><small>Trace decisions and catch conflicts early.</small></button><button type="button" data-v10-help-nav="publish"><strong>Shipping checklist</strong><small>Validate before moving the game to players.</small></button></div><section><h3>Useful shortcuts</h3><div class="v10-shortcut-list"><span><kbd>Ctrl K</kbd> Find anything</span><span><kbd>Ctrl S</kbd> Save</span><span><kbd>Ctrl Z</kbd> Undo</span><span><kbd>?</kbd> Help</span></div></section></form></dialog>`; }
    function onboardingMarkup() { return `<dialog id="v10Onboarding" class="v10-onboarding"><form method="dialog"><div class="v10-onboarding-art"><span>WHEN</span><span>IF</span><span>THEN</span></div><div class="v10-onboarding-copy"><span class="v10-kicker">WELCOME TO VERSION 10</span><h2 id="v10OnboardingTitle">Everything has a home now.</h2><p id="v10OnboardingText">Use the big workspace bar to move between Maps, Events, World Recipes, testing, and shipping.</p><div id="v10OnboardingDots" class="v10-dots"></div><div class="v10-onboarding-actions"><button id="v10OnboardingSkip" value="skip">Skip</button><button id="v10OnboardingNext" type="button" class="v10-big-primary">Next</button></div></div></form></dialog>`; }

    function markAdvancedControls() {
        document.querySelectorAll("textarea").forEach(textarea => { const text = textarea.closest("label")?.textContent || ""; if (/JSON|raw|canonical/i.test(text)) textarea.closest("label")?.classList.add("v10-advanced-control"); });
        document.querySelectorAll("details").forEach(details => { if (/raw|Git workspace|tile flag|advanced/i.test(details.querySelector("summary")?.textContent || "")) details.classList.add("v10-advanced-control"); });
    }

    function setMode(mode) {
        model.mode = mode === "pro" ? "pro" : "simple";
        document.documentElement.dataset.v10Mode = model.mode;
        document.querySelectorAll("[data-v10-mode]").forEach(button => button.classList.toggle("active", button.dataset.v10Mode === model.mode));
        persist(); announce(`${model.mode === "simple" ? "Simple" : "Pro"} interface enabled.`);
    }

    function selectInspector(panelId) {
        const button = document.querySelector(`#inspectorTabs [data-panel="${panelId}"]`); button?.click();
    }

    function navigate(id) {
        const workspace = WORKSPACES[id] || WORKSPACES.home; model.workspace = id in WORKSPACES ? id : "home"; persist();
        $("v10Home").classList.toggle("hidden", model.workspace !== "home");
        $("v10Workbench").classList.add("hidden"); document.querySelector(".workspace").classList.toggle("hidden", model.workspace === "home");
        if (workspace.panel) { document.querySelector(".workspace").classList.remove("hidden"); selectInspector(workspace.panel); }
        if (workspace.view) { document.querySelector(".workspace").classList.add("hidden"); renderWorkbench(workspace.view); }
        document.querySelectorAll("[data-v10-workspace]").forEach(button => button.classList.toggle("active", button.dataset.v10Workspace === model.workspace));
        if (model.workspace === "recipes") setTimeout(() => { enhanceRecipeForm(); renderRecipeGraph(); drawRecipeOverlay(); }, 0);
        announce(`${workspace.label} workspace. ${workspace.description}`);
    }

    function renderWorkbench(view) {
        $("v10Workbench").classList.remove("hidden");
        if (view === "packs") renderPackWorkbench(); else if (view === "test") renderTestWorkbench(); else renderPublishWorkbench();
    }

    function openCommandPalette() { const dialog = $("v10CommandPalette"); renderCommands(""); dialog.showModal(); setTimeout(() => $("v10CommandInput").focus(), 0); }
    function renderCommands(query) { const value = String(query || "").toLowerCase(); const commands = COMMANDS.filter(command => !value || `${command.label} ${command.hint}`.toLowerCase().includes(value)); $("v10CommandList").innerHTML = commands.length ? commands.map((command, index) => `<button type="button" role="option" data-v10-command="${command.id}" class="${index === 0 ? "selected" : ""}"><span><strong>${escapeHtml(command.label)}</strong><small>${escapeHtml(command.hint)}</small></span><kbd>↵</kbd></button>`).join("") : '<div class="v10-no-results">No matching tools. Try “recipe”, “save”, or “test”.</div>'; }
    function runCommand(id) { const command = COMMANDS.find(item => item.id === id); if (!command) return; $("v10CommandPalette").close(); model.commandHistory.unshift(id); model.commandHistory = [...new Set(model.commandHistory)].slice(0, 10); persist(); Promise.resolve(command.run()).catch(reportError); }

    function openHelp() { $("v10Help").showModal(); }
    const TOUR = [
        ["Everything has a home now.", "Use the big workspace bar to move between Maps, Events, World Recipes, testing, and shipping."],
        ["Simple first. Power when you want it.", "Simple mode hides implementation details. Switch to Pro whenever you need raw data, Git, or deep diagnostics."],
        ["Recipes read like a sentence.", "Build WHEN → IF → THEN flows visually, inspect the map overlay, and ask the debugger why something did or did not run."],
        ["Check before you ship.", "Scenario tests, conflict checks, backups, compatibility checks, and a production bundle live together in Ship."]
    ];
    let tourStep = 0;
    function showOnboarding(force = false) { if (model.onboardingComplete && !force) return; tourStep = 0; renderTour(); $("v10Onboarding").showModal(); }
    function renderTour() { $("v10OnboardingTitle").textContent = TOUR[tourStep][0]; $("v10OnboardingText").textContent = TOUR[tourStep][1]; $("v10OnboardingDots").innerHTML = TOUR.map((_, index) => `<i class="${index === tourStep ? "active" : ""}"></i>`).join(""); $("v10OnboardingNext").textContent = tourStep === TOUR.length - 1 ? "Start creating" : "Next"; }

    async function readCatalog() { try { const value = await api.readProjectJson("data/HybridWorldRecipes.json"); return value?.format === "HybridWorldRecipes" ? value : { format: "HybridWorldRecipes", version: 2, recipes: production.worldRecipes() }; } catch (_) { return { format: "HybridWorldRecipes", version: 2, recipes: production.worldRecipes() }; } }
    async function loadWorldData() { if (!api.state().projectOpen) return; const catalog = await readCatalog(); if (catalog.world) model.world = Object.assign(clone(defaults.world), clone(catalog.world)); if (Array.isArray(catalog.packs)) model.packs = clone(catalog.packs); persist(); updateHome(); }
    async function saveWorldData(message = "World systems saved.") { if (!api.state().projectOpen) throw new Error("Open an RPG Maker project to save world systems."); const catalog = await readCatalog(); catalog.version = Math.max(2, integer(catalog.version, 2)); catalog.recipes = production.worldRecipes(); catalog.world = clone(model.world); catalog.packs = clone(model.packs); await api.writeProjectJson("data/HybridWorldRecipes.json", catalog); persist(); api.status(message); announce(message); return catalog; }

    let worldSystemTab = "clock";
    function renderWorldSystems() {
        const target = $("v10WorldSystemBody"); if (!target) return; const clock = model.world.clock || defaults.world.clock;
        if (worldSystemTab === "clock") target.innerHTML = `<div class="v10-world-editor"><div class="v10-world-preview clock"><span>${String(integer(clock.hour, 8)).padStart(2, "0")}:${String(integer(clock.minuteOfHour, 0)).padStart(2, "0")}</span><small>Day ${integer(clock.day, 1)} · ${escapeHtml((clock.seasons || ["spring"])[Math.floor((integer(clock.day, 1) - 1) / Math.max(1, integer(clock.daysPerSeason, 30))) % Math.max(1, (clock.seasons || []).length)] || "spring")}</small></div><div class="v10-world-fields"><label>Starting day<input id="v10ClockDay" type="number" min="1" value="${integer(clock.day, 1)}"></label><div class="form-grid"><label>Hour<input id="v10ClockHour" type="number" min="0" max="23" value="${integer(clock.hour, 8)}"></label><label>Minute<input id="v10ClockMinute" type="number" min="0" max="59" value="${integer(clock.minuteOfHour, 0)}"></label></div><div class="form-grid"><label>Frames per minute<input id="v10ClockRate" type="number" min="1" value="${integer(clock.framesPerMinute, 60)}"></label><label>Days per season<input id="v10SeasonDays" type="number" min="1" value="${integer(clock.daysPerSeason, 30)}"></label></div><label>Seasons<input id="v10Seasons" value="${escapeHtml((clock.seasons || []).join(", "))}"></label><label class="toggle"><input id="v10ClockEnabled" type="checkbox" ${clock.enabled !== false ? "checked" : ""}><span>Clock advances during play</span></label><button id="v10ApplyWorldSystem" type="button">Apply time settings</button></div></div>`;
        else {
            const values = model.world[worldSystemTab] || []; const nouns = { zones: ["Zone", "A named area that can trigger enter and exit rules."], entities: ["Place", "A settlement, region, faction, or landmark with persistent state."], resources: ["Resource", "Something that can be harvested and later respawn."], variants: ["Map Variant", "A named alternate form activated by a recipe or change set."] }; const [noun, hint] = nouns[worldSystemTab];
            target.innerHTML = `<div class="v10-world-list">${values.length ? values.map(value => `<button type="button" data-v10-world-id="${escapeHtml(value.id)}"><span>${worldSystemTab === "zones" ? "◎" : worldSystemTab === "resources" ? "♢" : worldSystemTab === "variants" ? "▧" : "⌂"}</span><div><strong>${escapeHtml(value.name || value.id)}</strong><small>${escapeHtml(value.state || value.type || value.id)}</small></div><i>›</i></button>`).join("") : `<div class="v10-empty-friendly"><span>＋</span><strong>No ${noun.toLowerCase()}s yet</strong><p>${escapeHtml(hint)}</p></div>`}</div><div class="v10-world-fields"><span class="v10-kicker">NEW ${noun.toUpperCase()}</span><label>Name<input id="v10WorldName" value="New ${escapeHtml(noun)}"></label><label>Stable ID<input id="v10WorldId" value="new-${safeId(noun)}"></label>${worldSystemFields(worldSystemTab)}<div class="button-row"><button id="v10ApplyWorldSystem" type="button" class="v10-big-primary">Add ${escapeHtml(noun)}</button><button id="v10DeleteWorldSystem" type="button" class="danger" disabled>Delete selected</button></div></div>`;
        }
        $("v10ApplyWorldSystem").onclick = safe(applyWorldSystemForm); if ($("v10DeleteWorldSystem")) $("v10DeleteWorldSystem").onclick = safe(deleteSelectedWorldSystem); target.querySelector(".v10-world-list")?.addEventListener("click", selectWorldSystem);
    }

    function worldSystemFields(tab) {
        if (tab === "zones") return `<label>Map IDs<input id="v10WorldMaps" placeholder="1, 2, 5"></label><label>Rectangle (x, y, width, height)<input id="v10WorldRect" placeholder="10, 8, 6, 4"></label><label>Region IDs<input id="v10WorldRegions" placeholder="20, 21"></label><label>Tags<input id="v10WorldTags" placeholder="outdoors, forest"></label>`;
        if (tab === "entities") return `<label>Kind<select id="v10WorldType"><option value="settlement">Settlement</option><option value="region">Region</option><option value="faction">Faction</option><option value="landmark">Landmark</option></select></label><label>Starting state<input id="v10WorldState" value="normal"></label><label>Tags<input id="v10WorldTags" placeholder="town, friendly"></label><label>Properties JSON<textarea id="v10WorldProperties" rows="3">{}</textarea></label>`;
        if (tab === "resources") return `<div class="form-grid"><label>Starting amount<input id="v10WorldQuantity" type="number" min="0" value="1"></label><label>Capacity<input id="v10WorldCapacity" type="number" min="1" value="1"></label></div><label>Respawn after world minutes<input id="v10WorldRespawn" type="number" min="0" value="1440"></label><label>Tags<input id="v10WorldTags" placeholder="ore, renewable"></label>`;
        return `<label>Map ID<input id="v10WorldMapId" type="number" min="1" value="1"></label><label>Recipe to apply<select id="v10WorldRecipeId"><option value="">Choose a recipe</option>${production.worldRecipes().map(recipe => `<option value="${escapeHtml(recipe.id)}">${escapeHtml(recipe.name)}</option>`).join("")}</select></label><label>Change Set ID (optional)<input id="v10WorldChangeSet" placeholder="winter-town"></label>`;
    }

    function listNumbers(value) { return String(value || "").split(",").map(item => integer(item.trim(), NaN)).filter(Number.isFinite); }
    function applyWorldSystemForm() {
        if (worldSystemTab === "clock") model.world.clock = { enabled: $("v10ClockEnabled").checked, day: Math.max(1, integer($("v10ClockDay").value, 1)), hour: Math.max(0, Math.min(23, integer($("v10ClockHour").value, 8))), minuteOfHour: Math.max(0, Math.min(59, integer($("v10ClockMinute").value))), framesPerMinute: Math.max(1, integer($("v10ClockRate").value, 60)), daysPerSeason: Math.max(1, integer($("v10SeasonDays").value, 30)), seasons: $("v10Seasons").value.split(",").map(item => item.trim()).filter(Boolean) };
        else {
            const id = safeId($("v10WorldId").value); if (!id) throw new Error("Add a stable ID using letters, numbers, dots, colons, underscores, or hyphens."); let value = { id, name: $("v10WorldName").value.trim() || id };
            if (worldSystemTab === "zones") { const rect = listNumbers($("v10WorldRect").value); Object.assign(value, { mapIds: listNumbers($("v10WorldMaps").value), regions: listNumbers($("v10WorldRegions").value), tags: $("v10WorldTags").value.split(",").map(item => item.trim()).filter(Boolean), rect: rect.length >= 4 ? { x: rect[0], y: rect[1], width: Math.max(1, rect[2]), height: Math.max(1, rect[3]) } : null }); }
            else if (worldSystemTab === "entities") Object.assign(value, { type: $("v10WorldType").value, state: $("v10WorldState").value.trim() || "normal", tags: $("v10WorldTags").value.split(",").map(item => item.trim()).filter(Boolean), properties: parseJson($("v10WorldProperties").value, {}) });
            else if (worldSystemTab === "resources") Object.assign(value, { quantity: Math.max(0, Number($("v10WorldQuantity").value) || 0), capacity: Math.max(1, Number($("v10WorldCapacity").value) || 1), respawnMinutes: Math.max(0, integer($("v10WorldRespawn").value)), tags: $("v10WorldTags").value.split(",").map(item => item.trim()).filter(Boolean) });
            else Object.assign(value, { mapId: Math.max(1, integer($("v10WorldMapId").value, 1)), recipeId: $("v10WorldRecipeId").value, changeSetId: $("v10WorldChangeSet").value.trim(), enabled: true });
            const values = model.world[worldSystemTab]; const index = values.findIndex(item => item.id === id); if (index >= 0) values[index] = value; else values.push(value);
        }
        persist(); renderWorldSystems(); api.status(`${worldSystemTab === "clock" ? "Time settings" : "World system"} updated. Save World Systems to write the project file.`);
    }

    let selectedWorldSystemId = "";
    function selectWorldSystem(event) { const button = event.target.closest("[data-v10-world-id]"); if (!button) return; selectedWorldSystemId = button.dataset.v10WorldId; const value = model.world[worldSystemTab].find(item => item.id === selectedWorldSystemId); if (!value) return; $("v10WorldName").value = value.name || value.id; $("v10WorldId").value = value.id; $("v10DeleteWorldSystem").disabled = false; if (worldSystemTab === "zones") { $("v10WorldMaps").value = (value.mapIds || []).join(", "); $("v10WorldRect").value = value.rect ? [value.rect.x, value.rect.y, value.rect.width, value.rect.height].join(", ") : ""; $("v10WorldRegions").value = (value.regions || []).join(", "); $("v10WorldTags").value = (value.tags || []).join(", "); } else if (worldSystemTab === "entities") { $("v10WorldType").value = value.type || "settlement"; $("v10WorldState").value = value.state || "normal"; $("v10WorldTags").value = (value.tags || []).join(", "); $("v10WorldProperties").value = JSON.stringify(value.properties || {}, null, 2); } else if (worldSystemTab === "resources") { $("v10WorldQuantity").value = value.quantity ?? 1; $("v10WorldCapacity").value = value.capacity ?? 1; $("v10WorldRespawn").value = value.respawnMinutes ?? 0; $("v10WorldTags").value = (value.tags || []).join(", "); } else { $("v10WorldMapId").value = value.mapId || 1; $("v10WorldRecipeId").value = value.recipeId || ""; $("v10WorldChangeSet").value = value.changeSetId || ""; } }
    function deleteSelectedWorldSystem() { if (!selectedWorldSystemId) return; model.world[worldSystemTab] = model.world[worldSystemTab].filter(item => item.id !== selectedWorldSystemId); selectedWorldSystemId = ""; persist(); renderWorldSystems(); }
    function wireWorldSystems() { $("v10WorldSystems").querySelector("nav").onclick = event => { const button = event.target.closest("[data-v10-world-tab]"); if (!button) return; worldSystemTab = button.dataset.v10WorldTab; selectedWorldSystemId = ""; document.querySelectorAll("[data-v10-world-tab]").forEach(item => item.classList.toggle("active", item === button)); renderWorldSystems(); }; $("v10SaveWorldSystems").onclick = safe(() => saveWorldData()); renderWorldSystems(); }

    function selectedRecipe() { return production.selectedWorldRecipe() || (() => { try { return { id: $("v9RecipeId").value, name: $("v9RecipeName").value, triggers: [], conditions: parseJson($("v9RecipeConditionsJson").value, { all: [] }), actions: parseJson($("v9RecipeActionsJson").value, []) }; } catch (_) { return null; } })(); }

    function enhanceRecipeForm() {
        const form = $("v9RecipeForm"); if (!form || form.classList.contains("hidden")) return;
        if (!$("v10RecipeExperience")) {
            const description = $("v9RecipeDescription").closest("label");
            description.insertAdjacentHTML("afterend", `<section id="v10RecipeExperience" class="v10-recipe-experience"><header><div><span class="v10-kicker">VISUAL RECIPE</span><h3>Build the rule as a sentence</h3></div><div class="v10-segmented"><button type="button" data-v10-recipe-view="build" class="active">Build</button><button type="button" data-v10-recipe-view="debug">Debug</button><button type="button" data-v10-recipe-view="map">Map</button></div></header><div id="v10RecipeGraph" class="v10-recipe-graph" aria-label="Recipe flow"></div><div id="v10RecipeBuilder" class="v10-friendly-builder"><article><span class="v10-step when">1</span><div><strong>WHEN this happens</strong><label>Trigger<select id="v10FriendlyTrigger"><option value="mapEnter">Player enters a map</option><option value="zoneEnter">Player enters a zone</option><option value="interaction">Player interacts</option><option value="timeChange">Time changes</option><option value="seasonChange">Season changes</option><option value="switchChange">A switch changes</option><option value="variableChange">A variable changes</option><option value="custom">A named signal is sent</option></select></label><button id="v10AddFriendlyTrigger" type="button">Add trigger</button></div></article><article><span class="v10-step if">2</span><div><strong>IF these rules pass</strong><div class="v10-mini-grid"><select id="v10FriendlyCondition"><option value="switch">Switch</option><option value="variable">Variable</option><option value="state">World state</option><option value="fact">World fact</option><option value="zone">Inside zone</option><option value="time">World time</option><option value="season">Season</option><option value="resource">Resource amount</option><option value="worldEntity">Region / settlement state</option><option value="proximity">Near a point</option><option value="lineOfSight">Can see a point</option></select><input id="v10FriendlyConditionKey" placeholder="ID or name"><select id="v10FriendlyConditionOperator"><option value="===">is</option><option value="!==">is not</option><option value=">=">at least</option><option value="<=">at most</option><option value="in">is one of</option></select><input id="v10FriendlyConditionValue" placeholder="Value"></div><button id="v10AddFriendlyCondition" type="button">Add condition</button></div></article><article><span class="v10-step then">3</span><div><strong>THEN change the world</strong><div class="v10-mini-grid"><select id="v10FriendlyAction"><option value="setSwitch">Set a switch</option><option value="setVariable">Change a variable</option><option value="setState">Set world state</option><option value="addFact">Add world fact</option><option value="schedule">Schedule a recipe</option><option value="setClock">Change world time</option><option value="updateEntity">Change settlement / region</option><option value="harvestResource">Harvest resource</option><option value="applyVariant">Apply map variant</option><option value="commonEvent">Run common event</option><option value="weather">Change weather</option><option value="graftPrefab">Place prefab</option><option value="message">Show message</option></select><input id="v10FriendlyActionKey" placeholder="ID or name"><input id="v10FriendlyActionValue" placeholder="Value"></div><button id="v10AddFriendlyAction" type="button">Add action</button></div></article></div><div id="v10RecipeDebug" class="v10-recipe-debug hidden"><div class="v10-debug-toolbar"><button id="v10ExplainRecipe" type="button" class="v10-big-primary">Explain this recipe</button><button id="v10RecipeBreakpoint" type="button">Add breakpoint</button><button id="v10PushRecipeLive" type="button">Send to playtest</button></div><div id="v10ExplainReport" class="v10-explain-report">Choose “Explain this recipe” to see each decision in plain language.</div></div><div id="v10RecipeMap" class="v10-recipe-map-view hidden"><p>A colored overlay is drawn on the map for tile, area, prefab, zone, and position blocks.</p><label class="toggle"><input id="v10OverlayToggle" type="checkbox" checked><span>Show recipe overlay</span></label><div id="v10OverlayLegend" class="v10-overlay-legend"><span><i class="when"></i> Trigger / condition</span><span><i class="then"></i> World change</span></div></div></section>`);
            wireRecipeExperience(); markAdvancedControls();
        }
        $("v10OverlayToggle").checked = model.overlayEnabled !== false; renderRecipeGraph();
        const recipe = selectedRecipe(); $("v10RecipeBreakpoint").classList.toggle("active", !!recipe && model.breakpoints.includes(recipe.id)); $("v10RecipeBreakpoint").textContent = recipe && model.breakpoints.includes(recipe.id) ? "Breakpoint on" : "Add breakpoint";
    }

    function conditionSummary(condition) { if (!condition) return "Always"; if (condition.all) return `${condition.all.length} condition${condition.all.length === 1 ? "" : "s"} must pass`; if (condition.any) return `Any of ${condition.any.length} conditions may pass`; return `${condition.type || "condition"} ${condition.id ?? condition.key ?? condition.name ?? ""} ${condition.operator || "is"} ${JSON.stringify(condition.value ?? condition.state ?? "")}`.trim(); }
    function actionSummary(action) { const names = { setSwitch: "Set switch", setVariable: "Change variable", setState: "Remember world state", addFact: "Add world fact", schedule: "Schedule recipe", setClock: "Change time", updateEntity: "Update place", harvestResource: "Harvest resource", applyVariant: "Apply map variant", commonEvent: "Run common event", weather: "Change weather", graftPrefab: "Place prefab", fillTiles: "Fill tiles", setTile: "Set tile", message: "Show message" }; return `${names[action.type] || action.type || "Action"} ${action.id ?? action.key ?? action.name ?? action.recipeId ?? action.variantId ?? ""}`.trim(); }
    function renderRecipeGraph() {
        const target = $("v10RecipeGraph"); if (!target) return; let conditions = { all: [] }; let actions = [];
        try { conditions = parseJson($("v9RecipeConditionsJson").value, { all: [] }); actions = parseJson($("v9RecipeActionsJson").value, []); } catch (_) { /* existing editor reports malformed JSON */ }
        const triggers = [...document.querySelectorAll("[data-recipe-trigger]:checked")].map(input => input.closest("label")?.textContent.trim() || input.dataset.recipeTrigger);
        const conditionValues = conditions.all || conditions.any || (conditions.type ? [conditions] : []);
        const column = (kind, title, values, summary) => `<div class="v10-flow-column ${kind}"><header><span>${kind === "when" ? "1" : kind === "if" ? "2" : "3"}</span><strong>${title}</strong></header><div>${values.length ? values.map((value, index) => `<button type="button" data-v10-flow-kind="${kind}" data-v10-flow-index="${index}"><i></i><span>${escapeHtml(summary(value))}</span></button>`).join("") : `<button type="button" class="empty"><i></i><span>${kind === "if" ? "Always" : "Add a block below"}</span></button>`}</div></div>`;
        target.innerHTML = `${column("when", "WHEN", triggers, value => value)}<span class="v10-flow-arrow">›</span>${column("if", "IF", conditionValues, conditionSummary)}<span class="v10-flow-arrow">›</span>${column("then", "THEN", Array.isArray(actions) ? actions : [], actionSummary)}`;
        drawRecipeOverlay();
    }

    function friendlyCondition() { const type = $("v10FriendlyCondition").value; const key = $("v10FriendlyConditionKey").value.trim(); const value = valueFromText($("v10FriendlyConditionValue").value); const condition = { type, operator: $("v10FriendlyConditionOperator").value, value }; if (["switch", "variable"].includes(type)) condition.id = integer(key, 1); else if (["state"].includes(type)) condition.key = key || "world.flag"; else if (type === "fact") condition.name = key || "story.fact"; else if (type === "zone") { condition.id = key || "zone-id"; delete condition.value; delete condition.operator; } else if (type === "season") { condition.seasons = Array.isArray(value) ? value : String(value || key).split(",").map(item => item.trim()).filter(Boolean); delete condition.value; } else if (type === "resource") condition.id = key || "resource-id"; else if (type === "worldEntity") { condition.id = key || "place-id"; condition.state = value; delete condition.value; } else if (["proximity", "lineOfSight"].includes(type)) { const [x, y] = key.split(","); condition.x = integer(x); condition.y = integer(y); if (type === "proximity") condition.distance = Number(value) || 1; delete condition.value; } else if (type === "time") { condition.unit = "hour"; condition.value = Number(value || key) || 0; } return condition; }
    function friendlyAction() { const type = $("v10FriendlyAction").value; const key = $("v10FriendlyActionKey").value.trim(); const value = valueFromText($("v10FriendlyActionValue").value); const action = { type, value }; if (["setSwitch", "setVariable", "commonEvent"].includes(type)) action.id = integer(key, 1); else if (type === "setState") action.key = key || "world.flag"; else if (type === "addFact") action.name = key || "story.fact"; else if (type === "schedule") { action.recipeId = key || $("v9RecipeId").value; action.minutes = Number(value) || 60; delete action.value; } else if (type === "setClock") { action.hour = Number(key || value) || 8; action.minuteOfHour = 0; delete action.value; } else if (type === "updateEntity") { action.id = key || "place-id"; action.state = value || "changed"; delete action.value; } else if (type === "harvestResource") { action.id = key || "resource-id"; action.amount = Number(value) || 1; delete action.value; } else if (type === "applyVariant") { action.id = key || "variant-id"; delete action.value; } else if (type === "weather") { action.weather = key || value || "rain"; action.power = 5; action.duration = 60; delete action.value; } else if (type === "graftPrefab") { action.name = key || value || "Prefab Name"; action.x = { context: "x" }; action.y = { context: "y" }; delete action.value; } else if (type === "message") { action.text = String(value || key || "The world changed."); delete action.value; } return action; }

    function wireRecipeExperience() {
        $("v10AddFriendlyTrigger").onclick = () => { const type = $("v10FriendlyTrigger").value; const checkbox = [...document.querySelectorAll("[data-recipe-trigger]")].find(input => input.dataset.recipeTrigger.toLowerCase() === type.toLowerCase()); if (checkbox) checkbox.checked = true; else { const advanced = parseJson($("v9RecipeTriggersJson").value, []); advanced.push(type === "custom" ? { type: "custom", name: "mySignal" } : { type }); $("v9RecipeTriggersJson").value = JSON.stringify(advanced, null, 2); } renderRecipeGraph(); };
        $("v10AddFriendlyCondition").onclick = () => { const tree = parseJson($("v9RecipeConditionsJson").value, { all: [] }); tree.all ||= []; tree.all.push(friendlyCondition()); $("v9RecipeConditionsJson").value = JSON.stringify(tree, null, 2); $("v9RecipeConditionsJson").dispatchEvent(new Event("input")); renderRecipeGraph(); };
        $("v10AddFriendlyAction").onclick = () => { const actions = parseJson($("v9RecipeActionsJson").value, []); actions.push(friendlyAction()); $("v9RecipeActionsJson").value = JSON.stringify(actions, null, 2); $("v9RecipeActionsJson").dispatchEvent(new Event("input")); renderRecipeGraph(); };
        document.querySelectorAll("[data-v10-recipe-view]").forEach(button => button.onclick = () => { document.querySelectorAll("[data-v10-recipe-view]").forEach(item => item.classList.toggle("active", item === button)); $("v10RecipeBuilder").classList.toggle("hidden", button.dataset.v10RecipeView !== "build"); $("v10RecipeDebug").classList.toggle("hidden", button.dataset.v10RecipeView !== "debug"); $("v10RecipeMap").classList.toggle("hidden", button.dataset.v10RecipeView !== "map"); if (button.dataset.v10RecipeView === "map") drawRecipeOverlay(); });
        $("v10ExplainRecipe").onclick = safe(explainRecipeInStudio); $("v10RecipeBreakpoint").onclick = () => { const recipe = selectedRecipe(); if (!recipe) return; if (model.breakpoints.includes(recipe.id)) model.breakpoints = model.breakpoints.filter(id => id !== recipe.id); else model.breakpoints.push(recipe.id); persist(); enhanceRecipeForm(); };
        $("v10PushRecipeLive").onclick = safe(pushToPlaytest); $("v10OverlayToggle").onchange = () => { model.overlayEnabled = $("v10OverlayToggle").checked; persist(); drawRecipeOverlay(); };
        $("v10RecipeGraph").onclick = event => { const action = event.target.closest('[data-v10-flow-kind="then"]'); if (action) document.querySelector(`[data-recipe-action="${action.dataset.v10FlowIndex}"]`)?.click(); };
        for (const id of ["v9RecipeConditionsJson", "v9RecipeActionsJson", "v9RecipeTriggersJson"]) $(id).addEventListener("input", renderRecipeGraph);
        document.querySelectorAll("[data-recipe-trigger]").forEach(input => input.addEventListener("change", renderRecipeGraph));
    }

    async function explainRecipeInStudio() { const recipe = selectedRecipe(); if (!recipe) throw new Error("Select or create a World Recipe first."); await production.simulateWorldRecipe(); const source = $("v9RecipeReport"); const passed = !source.classList.contains("warning"); const entry = { id: uid("trace"), recipeId: recipe.id, at: Date.now(), passed, summary: source.textContent.trim() }; model.timeline.unshift(entry); model.timeline = model.timeline.slice(0, 100); persist(); $("v10ExplainReport").innerHTML = `<div class="v10-explain-head ${passed ? "pass" : "warn"}"><span>${passed ? "✓" : "?"}</span><div><strong>${passed ? "This recipe can run here" : "This recipe needs more information"}</strong><small>Dry run only — no project data changed</small></div></div><div class="v10-explain-body">${source.innerHTML}</div>`; }

    async function drawRecipeOverlay() { const overlay = $("v10RecipeOverlay"); if (!overlay) return; const state = api.state(); const recipe = selectedRecipe(); overlay.classList.toggle("hidden", model.workspace !== "recipes" || !model.overlayEnabled || !recipe || !state.activeMapId); if (overlay.classList.contains("hidden")) return; const canvas = $("mapCanvas"); overlay.width = canvas.clientWidth || canvas.width; overlay.height = canvas.clientHeight || canvas.height; const ctx = overlay.getContext("2d"); if (!ctx) return; ctx.clearRect(0, 0, overlay.width, overlay.height); const scale = 48 * (state.view?.zoom || 1); const panX = state.view?.panX || 0; const panY = state.view?.panY || 0; const blocks = [];
        const conditions = recipe.conditions?.all || recipe.conditions?.any || (recipe.conditions?.type ? [recipe.conditions] : []); for (const condition of conditions) if (condition.type === "position" || condition.type === "proximity") blocks.push({ kind: "if", x: integer(condition.x), y: integer(condition.y), width: 1, height: 1, label: condition.type });
        for (const action of recipe.actions || []) if (["setTile", "setRegion", "graftPrefab"].includes(action.type) && Number.isFinite(Number(action.x)) && Number.isFinite(Number(action.y))) blocks.push({ kind: "then", x: integer(action.x), y: integer(action.y), width: integer(action.width, 1), height: integer(action.height, 1), label: action.type }); else if (["fillTiles", "clearArea"].includes(action.type)) blocks.push({ kind: "then", x: integer(action.x), y: integer(action.y), width: Math.max(1, integer(action.width, 1)), height: Math.max(1, integer(action.height, 1)), label: action.type });
        for (const block of blocks) { const x = panX + block.x * scale; const y = panY + block.y * scale; ctx.fillStyle = block.kind === "then" ? "rgba(38,176,125,.28)" : "rgba(67,126,235,.28)"; ctx.strokeStyle = block.kind === "then" ? "#18a46f" : "#3977df"; ctx.lineWidth = 3; ctx.fillRect(x, y, block.width * scale, block.height * scale); ctx.strokeRect(x + 1.5, y + 1.5, block.width * scale - 3, block.height * scale - 3); ctx.fillStyle = "#fff"; ctx.font = "600 12px system-ui"; ctx.fillText(block.label, x + 7, y + 17); }
    }

    function setWorkbench(title, description, actions, body) { $("v10WorkbenchTitle").textContent = title; $("v10WorkbenchDescription").textContent = description; $("v10WorkbenchActions").innerHTML = actions; $("v10WorkbenchBody").innerHTML = body; }

    function renderPackWorkbench() { setWorkbench("World Packs", "Bundle recipes, prefabs, zones, resources, tests, and map variants into reusable content.", '<button id="v10ImportPack" type="button">Import pack</button><button id="v10CreatePack" type="button" class="v10-big-primary">Create pack</button>', `<div class="v10-dashboard-grid"><section class="v10-large-card"><header><div><span class="v10-kicker">INSTALLED CONTENT</span><h2>${model.packs.length} pack${model.packs.length === 1 ? "" : "s"}</h2></div></header><div id="v10PackList" class="v10-pack-list">${model.packs.length ? model.packs.map(pack => `<article><span class="v10-pack-gem">◇</span><div><strong>${escapeHtml(pack.name || pack.id)}</strong><small>${escapeHtml(pack.id)} · v${escapeHtml(pack.version || "1.0.0")}</small></div><button type="button" data-v10-export-pack="${escapeHtml(pack.id)}">Export</button><button type="button" data-v10-remove-pack="${escapeHtml(pack.id)}" class="danger">Remove</button></article>`).join("") : '<div class="v10-empty-friendly"><span>◇</span><strong>No World Packs yet</strong><p>Create one from this project or import a .htgworld file.</p></div>'}</div></section><section class="v10-side-card"><span class="v10-kicker">PACK BUILDER</span><h3>Share a complete feature</h3><label>Name<input id="v10PackName" value="${escapeHtml(api.projectInfo().name)} World Pack"></label><label>Stable ID<input id="v10PackId" value="${escapeHtml(safeId(api.projectInfo().name || "world-pack"))}"></label><label>Version<input id="v10PackVersion" value="1.0.0"></label><label>Dependencies<textarea id="v10PackDependencies" rows="3" placeholder="base-pack@1.0.0"></textarea></label><div class="v10-check-grid"><label><input id="v10PackRecipes" type="checkbox" checked> Recipes</label><label><input id="v10PackZones" type="checkbox" checked> Zones</label><label><input id="v10PackResources" type="checkbox" checked> Resources</label><label><input id="v10PackTests" type="checkbox" checked> Tests</label></div><button id="v10BuildPack" type="button" class="v10-big-primary">Build .htgworld pack</button><div id="v10PackReport" class="v10-friendly-report">Dependencies and ID conflicts are checked before import.</div></section></div>`); wirePackWorkbench(); }

    function worldPackFromProject() { const dependencies = $("v10PackDependencies").value.split(/\r?\n|,/).map(value => value.trim()).filter(Boolean).map(value => { const [id, minVersion] = value.split("@"); return minVersion ? { id, minVersion } : { id }; }); return { format: "HybridWorldPack", id: safeId($("v10PackId").value) || "world-pack", name: $("v10PackName").value.trim() || "World Pack", version: $("v10PackVersion").value.trim() || "1.0.0", pluginVersion: api.version, dependencies, recipes: $("v10PackRecipes").checked ? production.worldRecipes() : [], zones: $("v10PackZones").checked ? clone(model.world.zones) : [], entities: clone(model.world.entities), resources: $("v10PackResources").checked ? clone(model.world.resources) : [], variants: clone(model.world.variants), tests: $("v10PackTests").checked ? clone(model.world.tests) : [], stateDefaults: clone(model.world.stateDefaults), metadata: { createdWith: "Hybrid Tile Studio 10", createdAt: new Date().toISOString() } }; }
    function validatePackStudio(pack) { const errors = []; if (pack?.format !== "HybridWorldPack") errors.push("This is not a Hybrid World Pack."); if (!safeId(pack?.id)) errors.push("The pack needs a stable ID."); for (const dependency of pack?.dependencies || []) if (!model.packs.some(item => item.id === (dependency.id || dependency))) errors.push(`Missing dependency: ${dependency.id || dependency}`); const recipeIds = new Set(); for (const recipe of pack?.recipes || []) { if (!safeId(recipe.id)) errors.push("A recipe has an invalid ID."); if (recipeIds.has(recipe.id)) errors.push(`Duplicate recipe: ${recipe.id}`); recipeIds.add(recipe.id); } return { ok: errors.length === 0, errors, counts: { recipes: pack?.recipes?.length || 0, zones: pack?.zones?.length || 0, resources: pack?.resources?.length || 0, tests: pack?.tests?.length || 0 } }; }
    async function importWorldPackFile(file) { if (!file) return; if (file.size > 20 * 1024 * 1024) throw new Error("World Packs are limited to 20 MB."); const pack = parseJson(await file.text()); const report = validatePackStudio(pack); if (!report.ok) throw new Error(report.errors.join("; ")); const byId = new Map(production.worldRecipes().map(recipe => [recipe.id, recipe])); const conflicts = []; for (const recipe of pack.recipes || []) { if (byId.has(recipe.id)) conflicts.push(recipe.id); byId.set(recipe.id, clone(recipe)); } if (conflicts.length && typeof confirm === "function" && !confirm(`This pack updates ${conflicts.length} existing recipe(s):\n\n${conflicts.join("\n")}\n\nContinue with the update?`)) return false; await production.replaceWorldRecipes([...byId.values()]); const mergeById = (target, values) => { const map = new Map(target.map(value => [value.id, value])); for (const value of values || []) map.set(value.id, clone(value)); return [...map.values()]; }; model.world.zones = mergeById(model.world.zones, pack.zones); model.world.entities = mergeById(model.world.entities, pack.entities); model.world.resources = mergeById(model.world.resources, pack.resources); model.world.variants = mergeById(model.world.variants, pack.variants); model.world.tests = mergeById(model.world.tests, pack.tests); model.world.stateDefaults = Object.assign({}, model.world.stateDefaults, clone(pack.stateDefaults || {})); model.packs = mergeById(model.packs, [{ id: pack.id, name: pack.name || pack.id, version: pack.version || "1.0.0", dependencies: clone(pack.dependencies || []), installedAt: new Date().toISOString() }]); await saveWorldData(`Installed ${pack.name || pack.id}.`); renderPackWorkbench(); $("v10PackReport") && ($("v10PackReport").textContent = conflicts.length ? `Installed with ${conflicts.length} updated recipe(s): ${conflicts.join(", ")}` : `Installed ${report.counts.recipes} recipe(s) with no ID conflicts.`); }
    function wirePackWorkbench() { $("v10ImportPack").onclick = () => $("v10WorldPackFile").click(); $("v10CreatePack").onclick = () => $("v10PackName").focus(); $("v10BuildPack").onclick = () => { const pack = worldPackFromProject(); const report = validatePackStudio(pack); if (!report.ok) return $("v10PackReport").textContent = report.errors.join(" · "); api.download(`${pack.id}-${pack.version}.htgworld`, JSON.stringify(pack, null, 2)); if (!model.packs.some(item => item.id === pack.id)) { model.packs.push({ id: pack.id, name: pack.name, version: pack.version, dependencies: pack.dependencies, local: true }); persist(); } $("v10PackReport").textContent = `Built ${report.counts.recipes} recipes, ${report.counts.zones} zones, ${report.counts.resources} resources, and ${report.counts.tests} tests.`; }; $("v10PackList").onclick = event => { const remove = event.target.closest("[data-v10-remove-pack]"); const exportButton = event.target.closest("[data-v10-export-pack]"); if (remove) { model.packs = model.packs.filter(pack => pack.id !== remove.dataset.v10RemovePack); persist(); renderPackWorkbench(); } if (exportButton) { const pack = worldPackFromProject(); const installed = model.packs.find(value => value.id === exportButton.dataset.v10ExportPack); if (installed) Object.assign(pack, { id: installed.id, name: installed.name, version: installed.version }); api.download(`${pack.id}-${pack.version}.htgworld`, JSON.stringify(pack, null, 2)); } }; }

    function renderTestWorkbench() { const recipes = production.worldRecipes(); if (!model.selectedTestId && model.world.tests[0]) model.selectedTestId = model.world.tests[0].id; setWorkbench("Test Lab", "Prove world rules safely, explain failures, profile recipes, and send updates to a running playtest.", '<button id="v10PushLive" type="button">Send to playtest</button><button id="v10NewTest" type="button" class="v10-big-primary">New scenario</button>', `<div class="v10-test-layout"><aside><span class="v10-kicker">SCENARIOS</span><div id="v10TestList" class="v10-test-list">${model.world.tests.length ? model.world.tests.map(test => `<button type="button" data-v10-test-id="${escapeHtml(test.id)}" class="${test.id === model.selectedTestId ? "active" : ""}"><span>${escapeHtml(test.name || test.id)}</span><small>${escapeHtml(test.recipeId || "No recipe")}</small></button>`).join("") : '<div class="v10-empty-friendly"><span>✓</span><strong>No scenarios yet</strong><p>Add a small repeatable test for an important world rule.</p></div>'}</div></aside><main><section class="v10-large-card"><header><div><span class="v10-kicker">SCENARIO BUILDER</span><h2>Arrange → Run → Check</h2></div></header><div class="v10-test-steps"><article><span>1</span><div><strong>Arrange the world</strong><label>Scenario name<input id="v10TestName" value="New scenario"></label><label>Recipe<select id="v10TestRecipe">${recipes.map(recipe => `<option value="${escapeHtml(recipe.id)}">${escapeHtml(recipe.name)}</option>`).join("")}</select></label><label>Starting context<textarea id="v10TestContext" rows="4">{"mapId":1,"x":0,"y":0}</textarea></label><label class="v10-advanced-control">Initial values JSON<textarea id="v10TestInitial" rows="4">{"switches":{},"variables":{},"state":{},"facts":{}}</textarea></label></div></article><article><span>2</span><div><strong>Run without surprises</strong><p>The Studio performs a non-mutating dry run. Full state assertions run inside RPG Maker through the plugin test API.</p><button id="v10RunTest" type="button" class="v10-big-primary">Run selected scenario</button></div></article><article><span>3</span><div><strong>Check the outcome</strong><label>Expected values JSON<textarea id="v10TestExpect" rows="5">[{"type":"state","key":"world.flag","value":true}]</textarea></label><div class="button-row"><button id="v10SaveTest" type="button">Save scenario</button><button id="v10DuplicateTest" type="button">Duplicate</button><button id="v10DeleteTest" type="button" class="danger">Delete</button></div></div></article></div></section><section class="v10-large-card"><header><div><span class="v10-kicker">DEBUG TIMELINE</span><h2>What happened, in order</h2></div><button id="v10ClearTimeline" type="button">Clear</button></header><div id="v10Timeline" class="v10-timeline">${model.timeline.length ? model.timeline.map(entry => `<article class="${entry.passed ? "pass" : "warn"}"><time>${new Date(entry.at).toLocaleTimeString()}</time><span>${entry.passed ? "✓" : "?"}</span><div><strong>${escapeHtml(entry.recipeId)}</strong><small>${escapeHtml(entry.summary).slice(0, 240)}</small></div></article>`).join("") : '<div class="v10-empty-friendly"><span>◷</span><strong>The timeline is clear</strong><p>Run a scenario or explain a recipe to add a trace.</p></div>'}</div></section></main><aside class="v10-debug-sidebar"><span class="v10-kicker">LIVE DEBUG</span><h3>Playtest bridge</h3><p>Start the plugin bridge on the project’s <code>.hybrid</code> folder, then send changes here without restarting the game.</p><button id="v10PushLiveSide" type="button">Send current catalog</button><div id="v10BridgeStatus" class="v10-friendly-report">Not sent in this session.</div><h3>Breakpoints</h3><div>${model.breakpoints.length ? model.breakpoints.map(id => `<button type="button" data-v10-breakpoint="${escapeHtml(id)}">● ${escapeHtml(id)}</button>`).join("") : '<p>No recipe breakpoints.</p>'}</div></aside></div>`); wireTestWorkbench(); fillTestForm(); setMode(model.mode); }

    function selectedTest() { return model.world.tests.find(test => test.id === model.selectedTestId) || null; }
    function fillTestForm() { const test = selectedTest(); if (!test || !$("v10TestName")) return; $("v10TestName").value = test.name || test.id; $("v10TestRecipe").value = test.recipeId || ""; $("v10TestContext").value = JSON.stringify(test.context || {}, null, 2); $("v10TestInitial").value = JSON.stringify(test.initial || { switches: {}, variables: {}, state: {}, facts: {} }, null, 2); $("v10TestExpect").value = JSON.stringify(test.expect || [], null, 2); }
    function testFromForm(existingId = "") { const name = $("v10TestName").value.trim() || "World Recipe scenario"; return { id: existingId || safeId(name) || uid("scenario"), name, recipeId: $("v10TestRecipe").value, context: parseJson($("v10TestContext").value, {}), initial: parseJson($("v10TestInitial").value, {}), expect: parseJson($("v10TestExpect").value, []) }; }
    async function saveTest() { const current = selectedTest(); const test = testFromForm(current?.id); const index = model.world.tests.findIndex(value => value.id === test.id); if (index >= 0) model.world.tests[index] = test; else model.world.tests.push(test); model.selectedTestId = test.id; await saveWorldData(`Saved test “${test.name}”.`); renderTestWorkbench(); }
    async function runSelectedTest() { const test = testFromForm(selectedTest()?.id); const recipe = production.worldRecipes().find(value => value.id === test.recipeId); if (!recipe) throw new Error("Choose a recipe for this scenario."); navigate("recipes"); const escapedId = window.CSS?.escape ? window.CSS.escape(recipe.id) : recipe.id.replace(/["\\]/g, "\\$&"); const recipeButton = document.querySelector(`[data-recipe-id="${escapedId}"]`); recipeButton?.click(); setTimeout(async () => { enhanceRecipeForm(); await explainRecipeInStudio(); navigate("test"); }, 20); }
    function wireTestWorkbench() { $("v10NewTest").onclick = () => { const test = { id: uid("scenario"), name: "New scenario", recipeId: production.worldRecipes()[0]?.id || "", context: { mapId: 1, x: 0, y: 0 }, initial: { switches: {}, variables: {}, state: {}, facts: {} }, expect: [] }; model.world.tests.push(test); model.selectedTestId = test.id; persist(); renderTestWorkbench(); }; $("v10TestList").onclick = event => { const button = event.target.closest("[data-v10-test-id]"); if (button) { model.selectedTestId = button.dataset.v10TestId; persist(); renderTestWorkbench(); } }; $("v10SaveTest").onclick = safe(saveTest); $("v10RunTest").onclick = safe(runSelectedTest); $("v10DuplicateTest").onclick = () => { const current = selectedTest(); if (!current) return; const copy = clone(current); copy.id = uid(`${current.id}-copy`); copy.name += " Copy"; model.world.tests.push(copy); model.selectedTestId = copy.id; persist(); renderTestWorkbench(); }; $("v10DeleteTest").onclick = () => { model.world.tests = model.world.tests.filter(test => test.id !== model.selectedTestId); model.selectedTestId = model.world.tests[0]?.id || null; persist(); renderTestWorkbench(); }; $("v10ClearTimeline").onclick = () => { model.timeline = []; persist(); renderTestWorkbench(); }; $("v10PushLive").onclick = $("v10PushLiveSide").onclick = safe(pushToPlaytest); document.querySelector(".v10-debug-sidebar").onclick = event => { const button = event.target.closest("[data-v10-breakpoint]"); if (button) { model.breakpoints = model.breakpoints.filter(id => id !== button.dataset.v10Breakpoint); persist(); renderTestWorkbench(); } }; }

    function releaseChecks() { const recipes = production.worldRecipes(); const errors = []; const warnings = []; const ids = new Set(); for (const recipe of recipes) { if (!safeId(recipe.id)) errors.push(`Recipe “${recipe.name || "Unnamed"}” has an invalid ID.`); if (ids.has(recipe.id)) errors.push(`Recipe ID “${recipe.id}” is duplicated.`); ids.add(recipe.id); if (!recipe.actions?.length) warnings.push(`${recipe.name || recipe.id} has no actions.`); } for (const zone of model.world.zones) if (!zone.mapIds?.length && !zone.mapId) warnings.push(`Zone ${zone.name || zone.id} is not limited to a map.`); for (const variant of model.world.variants) if (variant.recipeId && !ids.has(variant.recipeId)) errors.push(`Variant ${variant.name || variant.id} references missing recipe ${variant.recipeId}.`); for (const test of model.world.tests) if (!ids.has(test.recipeId)) errors.push(`Test ${test.name || test.id} references missing recipe ${test.recipeId}.`); for (const pack of model.packs) for (const dependency of pack.dependencies || []) if (!model.packs.some(item => item.id === (dependency.id || dependency))) warnings.push(`Pack ${pack.id} is missing dependency ${dependency.id || dependency}.`); return { ok: errors.length === 0, errors, warnings, counts: { recipes: recipes.length, tests: model.world.tests.length, zones: model.world.zones.length, packs: model.packs.length } }; }
    function renderPublishWorkbench() { const report = releaseChecks(); setWorkbench("Ship", "One calm place for project health, compatibility, backups, tests, and the production bundle.", '<button id="v10SaveCheckpoint" type="button">Safety snapshot</button><button id="v10BuildProduction" type="button" class="v10-big-primary">Build production bundle</button>', `<div class="v10-publish-hero ${report.ok ? "ready" : "attention"}"><span>${report.ok ? "✓" : "!"}</span><div><span class="v10-kicker">RELEASE READINESS</span><h2>${report.ok ? "Your world data is ready for a full check." : `${report.errors.length} item${report.errors.length === 1 ? " needs" : "s need"} attention.`}</h2><p>${report.warnings.length} advisory note${report.warnings.length === 1 ? "" : "s"}. Building never overwrites source maps.</p></div><button id="v10RunReleaseCheck" type="button">Run full checkup</button></div><div class="v10-metric-row"><article><strong>${report.counts.recipes}</strong><span>World Recipes</span></article><article><strong>${report.counts.tests}</strong><span>Scenarios</span></article><article><strong>${report.counts.zones}</strong><span>World Zones</span></article><article><strong>${report.counts.packs}</strong><span>Content Packs</span></article></div><div class="v10-dashboard-grid"><section class="v10-large-card"><header><div><span class="v10-kicker">CHECKUP RESULTS</span><h2>Clear next steps</h2></div></header><div id="v10ReleaseReport" class="v10-release-list">${[...report.errors.map(message => ["error", message]), ...report.warnings.map(message => ["warning", message])].map(([kind, message]) => `<article class="${kind}"><span>${kind === "error" ? "!" : "i"}</span><div><strong>${kind === "error" ? "Fix before shipping" : "Worth reviewing"}</strong><p>${escapeHtml(message)}</p></div></article>`).join("") || '<article class="pass"><span>✓</span><div><strong>No recipe or world-data problems found</strong><p>Run the full checkup to include maps, assets, compatibility, and references.</p></div></article>'}</div></section><section class="v10-side-card"><span class="v10-kicker">PRODUCTION BUNDLE</span><h3>Only what the game needs</h3><p>Exports recipes and world systems without Studio history, reviews, previews, or editor preferences.</p><label class="toggle"><input id="v10StripDisabled" type="checkbox" checked><span>Remove disabled recipes</span></label><label class="toggle"><input id="v10IncludeTests" type="checkbox"><span>Include scenario definitions</span></label><button id="v10BuildProductionSide" type="button" class="v10-big-primary">Build bundle</button><hr><button id="v10OpenCompatibility" type="button">Compatibility Lab</button><button id="v10OpenRecovery" type="button">Backups and Recovery</button></section></div>`); wirePublishWorkbench(); }

    async function runReleaseCheck() { const local = releaseChecks(); $("validateButton").click(); const audit = api.state().projectOpen ? await api.auditProject().catch(error => ({ ok: false, errors: 1, issues: [{ message: error.message }] })) : { ok: false, errors: 1, issues: [{ message: "Open a project for map and reference checks." }] }; const messages = [...local.errors.map(message => ["error", message]), ...local.warnings.map(message => ["warning", message]), ...(audit.issues || []).map(issue => [issue.severity === "error" ? "error" : "warning", issue.message || String(issue)])]; $("v10ReleaseReport").innerHTML = messages.length ? messages.map(([kind, message]) => `<article class="${kind}"><span>${kind === "error" ? "!" : "i"}</span><div><strong>${kind === "error" ? "Fix before shipping" : "Worth reviewing"}</strong><p>${escapeHtml(message)}</p></div></article>`).join("") : '<article class="pass"><span>✓</span><div><strong>All checks passed</strong><p>Your maps and World Recipes passed this checkup.</p></div></article>'; api.status(`Checkup complete: ${messages.filter(item => item[0] === "error").length} error(s), ${messages.filter(item => item[0] === "warning").length} note(s).`); }
    async function buildProductionBundle() { const report = releaseChecks(); if (!report.ok) throw new Error("Resolve the red release-readiness items before building."); const catalog = await readCatalog(); catalog.recipes = production.worldRecipes().filter(recipe => !$("v10StripDisabled")?.checked || recipe.enabled !== false).map(recipe => { const copy = clone(recipe); delete copy.source; if (copy.metadata) { delete copy.metadata.thumbnail; delete copy.metadata.editor; } return copy; }); catalog.world = clone(model.world); if (!$("v10IncludeTests")?.checked) delete catalog.world.tests; delete catalog.packs; const bundle = { format: "HybridTileGraftProductionBundle", version: 1, pluginVersion: api.version, createdAt: new Date().toISOString(), catalog, manifest: { recipes: catalog.recipes.length, zones: catalog.world.zones?.length || 0, resources: catalog.world.resources?.length || 0, variants: catalog.world.variants?.length || 0, checksum: await api.checksum(catalog) } }; api.download(`HybridTileGraft-${safeId(api.projectInfo().name || "Game")}-Production.json`, JSON.stringify(bundle, null, 2)); api.status("Production bundle built. Source maps were not changed."); }
    function wirePublishWorkbench() { $("v10RunReleaseCheck").onclick = safe(runReleaseCheck); $("v10BuildProduction").onclick = $("v10BuildProductionSide").onclick = safe(buildProductionBundle); $("v10SaveCheckpoint").onclick = () => { const result = api.createSnapshot("Pre-release safety snapshot"); api.status(result ? "Safety snapshot created." : "Open a map before creating a snapshot."); }; $("v10OpenCompatibility").onclick = () => { document.querySelector(".workspace").classList.remove("hidden"); $("v10Workbench").classList.add("hidden"); selectInspector("projectPanel"); setTimeout(() => $("v9RunCompatibilityLab")?.focus(), 0); }; $("v10OpenRecovery").onclick = () => { document.querySelector(".workspace").classList.remove("hidden"); $("v10Workbench").classList.add("hidden"); selectInspector("historyPanel"); }; }

    async function pushToPlaytest() { const catalog = await saveWorldData("World data saved; preparing playtest update."); await api.writeProjectJson(".hybrid/HybridTileGraft.incoming.json", catalog); const message = "Sent to .hybrid/HybridTileGraft.incoming.json. A running bridge will reload it automatically."; if ($("v10BridgeStatus")) $("v10BridgeStatus").textContent = message; api.status(message); announce("World Recipes sent to playtest."); }

    function updateHome() { const info = api.projectInfo(); if (!$("v10HomeProject")) return; $("v10HomeProject").textContent = info.open ? info.name : "No project open"; const summary = production.modelSummary(); $("v10HomeSummary").textContent = info.open ? `${info.maps.length} maps · ${summary.recipes} World Recipes · ${model.world.tests.length} tests` : "Open an RPG Maker MZ folder to begin."; }

    function wireShell() {
        document.body.addEventListener("click", event => { const nav = event.target.closest("[data-v10-workspace]"); if (nav) navigate(nav.dataset.v10Workspace); });
        document.querySelector('[data-v10-home-action="open"]').onclick = () => $("openProjectButton").click(); document.querySelector('[data-v10-home-action="tour"]').onclick = () => showOnboarding(true);
        document.querySelectorAll("[data-v10-mode]").forEach(button => button.onclick = () => setMode(button.dataset.v10Mode)); $("v10SearchButton").onclick = openCommandPalette; $("v10HelpButton").onclick = openHelp; $("v10WorkbenchBack").onclick = () => navigate("home");
        $("v10CommandInput").oninput = event => renderCommands(event.target.value); $("v10CommandList").onclick = event => { const button = event.target.closest("[data-v10-command]"); if (button) runCommand(button.dataset.v10Command); };
        $("v10CommandInput").onkeydown = event => { const buttons = [...$("v10CommandList").querySelectorAll("button")]; let index = Math.max(0, buttons.findIndex(button => button.classList.contains("selected"))); if (event.key === "ArrowDown" || event.key === "ArrowUp") { event.preventDefault(); buttons[index]?.classList.remove("selected"); index = (index + (event.key === "ArrowDown" ? 1 : -1) + buttons.length) % Math.max(1, buttons.length); buttons[index]?.classList.add("selected"); buttons[index]?.scrollIntoView?.({ block: "nearest" }); } else if (event.key === "Enter") { event.preventDefault(); buttons[index]?.click(); } };
        $("v10Help").onclick = event => { const tour = event.target.closest("[data-v10-tour]"); const nav = event.target.closest("[data-v10-help-nav]"); if (tour) { $("v10Help").close(); showOnboarding(true); } if (nav) { $("v10Help").close(); navigate(nav.dataset.v10HelpNav); } };
        $("v10OnboardingNext").onclick = () => { if (tourStep < TOUR.length - 1) { tourStep++; renderTour(); } else { model.onboardingComplete = true; persist(); $("v10Onboarding").close(); navigate("home"); } }; $("v10OnboardingSkip").onclick = () => { model.onboardingComplete = true; persist(); };
        $("v10WorldPackFile").onchange = safe(event => importWorldPackFile(event.target.files?.[0]));
        window.addEventListener("keydown", event => { if ((event.ctrlKey || event.metaKey) && event.key.toLowerCase() === "k") { event.preventDefault(); openCommandPalette(); } else if (event.key === "?" && !/INPUT|TEXTAREA|SELECT/.test(event.target.tagName)) openHelp(); });
        document.addEventListener("HybridTileStudio:project-opened", () => loadWorldData().then(updateHome).catch(reportError));
        document.addEventListener("HybridTileStudio:recipes-saved", () => { if (!suppressRecipeSaveSync && api.state().projectOpen) saveWorldData("World Recipe catalog saved.").catch(reportError); });
        document.addEventListener("HybridTileStudio:world-pack-opened", event => { const text = JSON.stringify(event.detail?.value || {}); const file = { size: text.length, text: async () => text }; importWorldPackFile(file).then(() => navigate("content")).catch(reportError); });
        const recipeObserver = new MutationObserver(() => { if (model.workspace === "recipes") enhanceRecipeForm(); }); recipeObserver.observe($("v9RecipeForm"), { attributes: true, attributeFilter: ["class"] });
        for (const id of ["v9RecipeList", "v9NewRecipeButton", "v9DuplicateRecipeButton", "v9ApplyRecipeTemplate"]) $(id)?.addEventListener("click", () => setTimeout(() => { if (model.workspace === "recipes") { enhanceRecipeForm(); renderRecipeGraph(); } }, 0));
        if (typeof ResizeObserver === "function") { const canvasObserver = new ResizeObserver(() => drawRecipeOverlay()); canvasObserver.observe($("mapCanvas")); }
        let lastGamepad = 0; const pollGamepad = () => { if (!navigator.getGamepads) return requestAnimationFrame(pollGamepad); const pad = navigator.getGamepads()[0]; if (pad && Date.now() - lastGamepad > 180) { const focused = document.activeElement; const focusables = [...document.querySelectorAll("button:not(:disabled),input:not(:disabled),select:not(:disabled),textarea:not(:disabled)")].filter(element => element.offsetParent !== null); let index = Math.max(0, focusables.indexOf(focused)); if (pad.buttons[0]?.pressed) { focused?.click?.(); lastGamepad = Date.now(); } else if (pad.buttons[1]?.pressed && $("v10Workbench").classList.contains("hidden") === false) { navigate("home"); lastGamepad = Date.now(); } else if (pad.buttons[12]?.pressed || pad.buttons[14]?.pressed) { index = Math.max(0, index - 1); focusables[index]?.focus(); lastGamepad = Date.now(); } else if (pad.buttons[13]?.pressed || pad.buttons[15]?.pressed) { index = Math.min(focusables.length - 1, index + 1); focusables[index]?.focus(); lastGamepad = Date.now(); } } requestAnimationFrame(pollGamepad); }; if (!/HappyDOM/i.test(navigator.userAgent || "")) requestAnimationFrame(pollGamepad);
    }

    async function initialize() { injectShell(); wireShell(); wireWorldSystems(); setMode(model.mode); updateHome(); navigate(model.workspace || "home"); await loadWorldData(); renderWorldSystems(); if (!model.onboardingComplete && !/HappyDOM/i.test(navigator.userAgent || "")) setTimeout(showOnboarding, 250); document.dispatchEvent(new CustomEvent("HybridTileStudio:product-ready", { detail: { version: api.version, workspaces: Object.keys(WORKSPACES).length } })); }
    initialize().catch(reportError);
})();
